struct Compositor::Impl {
    // Holds the sokol_gfx pipeline + shader + quad buffers in Phase 2.
};

Compositor::Compositor(CompositorConfig cfg)
    : impl_(std::make_unique<Impl>()), cfg_(cfg) {}
